fn solve(nums: Vec<i64>, edges: Vec<Vec<i64>>) -> i64 {
    let n = nums.len();
    let mut adj = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    let mut count = 0;

    // Iterate over all non-empty subsets of nodes. 
    // A subset can be represented by a bitmask from 1 to 2^n - 1.
    for mask in 1..(1 << n) {
        let subset_nodes: Vec<usize> = (0..n).filter(|&i| (mask & (1 << i)) != 0).collect();

        // 1. Check if the sum of values in the subset is even.
        let mut sum: i64 = 0;
        for &i in &subset_nodes {
            sum += nums[i];
        }

        if sum % 2 != 0 {
            continue; // Sum is odd, skip this subset
        }

        // 2. Check if the induced subgraph is connected.
        if subset_nodes.is_empty() {
            continue; // Should not happen due to mask starting from 1
        }

        let start_node = subset_nodes[0];
        let mut visited = vec![false; n];
        let mut queue = std::collections::VecDeque::new();

        queue.push_back(start_node);
        visited[start_node] = true;
        let mut visited_count = 0;

        while let Some(u) = queue.pop_front() {
            visited_count += 1;

            for &v in &adj[u] {
                // Only consider edges where both endpoints are in the subset (induced subgraph)
                // and the neighbor 'v' has not been visited yet.
                if (mask & (1 << v)) != 0 && !visited[v] {
                    visited[v] = true;
                    queue.push_back(v);
                }
            }
        }

        // Check for connectivity: the number of visited nodes from the starting node
        // within the subset must equal the total number of nodes in the subset.
        if visited_count == subset_nodes.len() {
            count += 1;
        }
    }

    count
}
